 1	import { type FC, Suspense } from 'react';
 2	import Loading from 'src/overview/components/Loading';
 3	import TabTitle from 'src/overview/components/TabTitle';
 4	import { useK8sWatchForkliftController } from 'src/overview/hooks/useK8sWatchForkliftController';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { ResourceYAMLEditor } from '@openshift-console/dynamic-plugin-sdk';
 8	import { Bullseye, CardTitle } from '@patternfly/react-core';
 9	
10	const ForkliftControllerYAMLTab: FC = () => {
11	  const [forkliftController, loaded, loadError] = useK8sWatchForkliftController();
12	  const { t } = useForkliftTranslation();
13	  return (
14	    <Suspense
15	      fallback={
16	        <Bullseye>
17	          <Loading />
18	        </Bullseye>
19	      }
20	    >
21	      <CardTitle className="forklift-title pf-v6-u-p-lg pf-v6-u-pb-0">
22	        <TabTitle
23	          title={t('YAML')}
24	          helpContent={t(
25	            'You can write configuration files for the Migration Toolkit for Virtualization using YAML, a human-readable data serialization language.',
26	          )}
27	        />
28	      </CardTitle>
29	
30	      {forkliftController && loaded && !loadError && (
31	        <ResourceYAMLEditor header={t('Provider YAML')} initialResource={forkliftController} />
32	      )}
33	    </Suspense>
34	  );
35	};
36	
37	export default ForkliftControllerYAMLTab;

